mapper.insert:
/** CmmtCodeDao.insert */
insert into cmmt_code (
	code_group
	,code
	,code_nm
	,remark
	,code_type
	,enabled
	,sort_order
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	upper(#{codeGroup})
	,upper(#{code})
	,#{codeNm}
	,#{remark}
	,upper(#{codeType})
	,#{enabled}
	,#{sortOrder}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.update:
/** CmmtCodeDao.update */
update cmmt_code set
	code_nm    	= #{codeNm}
	,remark    	= #{remark}
	,code_Type  = upper(#{codeType})
	,enabled   	= #{enabled}
	,sort_order = #{sortOrder}
where
	code_group = upper(#{codeGroup})
	and code = upper(#{code})
